import{_ as e,o as t,c as o,a3 as i}from"./chunks/framework.CjquFG0V.js";const p=JSON.parse('{"title":"35. Higher Qualifications Allowance","description":"","frontmatter":{"title":"35. Higher Qualifications Allowance","eba":"Allied Health Professionals 2021-2026","topics":["allowances"]},"headers":[],"relativePath":"ebas/allied-health/allowances/35-higher-qualifications-allowance.md","filePath":"ebas/allied-health/allowances/35-higher-qualifications-allowance.md"}'),n={name:"ebas/allied-health/allowances/35-higher-qualifications-allowance.md"};function l(r,a,s,c,h,d){return t(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="_35-higher-qualifications-allowance" tabindex="-1">35. Higher Qualifications Allowance <a class="header-anchor" href="#_35-higher-qualifications-allowance" aria-label="Permalink to &quot;35. Higher Qualifications Allowance&quot;">​</a></h1><p><strong>35.1</strong> An Employee who holds an additional post graduate qualification which is of direct relevance to their current position or functional work area, will be paid an allowance of 7.5% of the AHP1 Grade 1, Year 2 rate.</p><p><strong>35.2</strong> An Employee who holds a doctorate which is of direct relevance to their current position or functional work area will be paid an allowance of 10% of the AHP1 Grade 1, Year 2 rate.</p><p><strong>35.3</strong> An Employee who receives an allowance under subclause 35.2 above cannot also receive an allowance under subclause 35.1 above.</p><p><strong>35.4</strong> The higher qualifications allowance is to be paid during all periods of leave except sick leave beyond 21 days and long service leave.</p><p><strong>35.5</strong> Definitions</p><p><strong>(a)</strong> A post graduate qualification includes a qualification that has been assessed as a Bachelor Honours Degree, Graduate Certificate, Graduate Diploma or Masters Degree (or equivalent to any of these) under the Australian Qualifications Framework level 8 or 9 criteria.</p><p><strong>(b)</strong> A doctorate includes a qualification that has been assessed as a Doctorate (or equivalent) under the Australian Qualifications Framework level 10 criteria.</p><p><strong>(c)</strong> For the avoidance of doubt, additional post graduate qualification in subclause 35.1 means a post graduate qualification held by the Employee that is in addition to the minimum qualification that is required to enable them entry into the relevant profession under the Agreement. It is not a post graduate qualification held by an Employee that is the only qualification they hold that allows them entry into the profession under the Agreement.</p>',9)])])}const f=e(n,[["render",l]]);export{p as __pageData,f as default};
